/**
 * Integration tests for the full notification pipeline.
 *
 * Tests the end-to-end flow: EventBus → NotificationService → Adapters → History
 * with preferences checking at each step.
 *
 * These tests wire up the full stack (no mocks) and verify that domain events
 * result in the correct notifications being delivered through each channel,
 * logged in history, and filtered by user preferences.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import { NotificationHistoryService, resetNotificationLogIdCounter } from '../../src/services/notification-history.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

// -- Test Fixtures --

function createTestUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-001',
    name: 'Alice Test',
    email: 'alice@example.com',
    phone: '+15551234567',
    role: 'member',
    createdAt: new Date('2026-01-01'),
    updatedAt: new Date('2026-01-01'),
    ...overrides,
  };
}

function createTestOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-001',
    userId: 'user-001',
    items: [
      { productId: 'prod-1', name: 'Widget', quantity: 2, unitPrice: 9.99 },
      { productId: 'prod-2', name: 'Gadget', quantity: 1, unitPrice: 24.99 },
    ],
    total: 44.97,
    status: 'pending',
    createdAt: new Date('2026-03-01'),
    updatedAt: new Date('2026-03-01'),
    ...overrides,
  };
}

// -- Full Pipeline Setup --

interface PipelineContext {
  db: Database;
  eventBus: EventBus;
  userRepo: UserRepository;
  prefsRepo: PreferencesRepository;
  logRepo: NotificationLogRepository;
  preferencesService: PreferencesService;
  historyService: NotificationHistoryService;
  notificationService: NotificationService;
  emailAdapter: EmailAdapter;
  smsAdapter: SmsAdapter;
  webhookAdapter: WebhookAdapter;
}

function setupPipeline(): PipelineContext {
  const db = new Database();
  const eventBus = new EventBus();

  // Repositories
  const userRepo = new UserRepository(db);
  const prefsRepo = new PreferencesRepository(db);
  const logRepo = new NotificationLogRepository(db);

  // Services
  const preferencesService = new PreferencesService(prefsRepo, userRepo);
  const historyService = new NotificationHistoryService(logRepo);

  // Notification service (subscribes to EventBus in constructor)
  const notificationService = new NotificationService(eventBus);

  // Adapters
  const emailAdapter = new EmailAdapter();
  const smsAdapter = new SmsAdapter({ fromNumber: '+15550000000' });
  const webhookAdapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify', secret: 'test-secret' });

  // Wire up
  notificationService.registerAdapter(emailAdapter);
  notificationService.registerAdapter(smsAdapter);
  notificationService.registerAdapter(webhookAdapter);
  notificationService.setPreferencesService(preferencesService);
  notificationService.setHistoryService(historyService);
  notificationService.setUserRepository(userRepo);

  return {
    db, eventBus, userRepo, prefsRepo, logRepo,
    preferencesService, historyService, notificationService,
    emailAdapter, smsAdapter, webhookAdapter,
  };
}

describe('Notification Pipeline Integration', () => {
  let ctx: PipelineContext;

  beforeEach(() => {
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    resetNotificationLogIdCounter();
    ctx = setupPipeline();
  });

  // ---- Email Channel ----

  describe('email channel end-to-end', () => {
    it('should deliver email notification when order:created is emitted', async () => {
      const user = createTestUser();
      ctx.userRepo.save(user);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      const emails = ctx.emailAdapter.getSentEmails();
      expect(emails.length).toBe(1);
      expect(emails[0].to).toBe('alice@example.com');
      expect(emails[0].subject).toContain('Order Confirmation');
      expect(emails[0].html).toContain('Widget x2');
      expect(emails[0].text).toContain('Gadget x1');
    });

    it('should deliver email notification when order:status-changed is emitted', async () => {
      const user = createTestUser();
      ctx.userRepo.save(user);
      const order = createTestOrder({ status: 'confirmed' });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order,
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      const emails = ctx.emailAdapter.getSentEmails();
      expect(emails.length).toBe(1);
      // For status-changed, recipient is userId (not email) because event doesn't include full user
      expect(emails[0].subject).toContain('Order Update');
      expect(emails[0].text).toContain('pending');
      expect(emails[0].text).toContain('confirmed');
    });
  });

  // ---- SMS Channel ----

  describe('SMS channel end-to-end', () => {
    it('should deliver SMS notification when user has a phone number (order:created)', async () => {
      const user = createTestUser({ phone: '+15559876543' });
      ctx.userRepo.save(user);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      const messages = ctx.smsAdapter.getSentMessages();
      expect(messages.length).toBe(1);
      expect(messages[0].to).toBe('+15559876543');
      expect(messages[0].from).toBe('+15550000000');
      expect(messages[0].body).toContain('Order Confirmation');
      expect(messages[0].body).toContain('Widget x2');
    });

    it('should deliver SMS for order:status-changed by looking up user phone from repository', async () => {
      const user = createTestUser({ phone: '+15559876543' });
      ctx.userRepo.save(user);
      const order = createTestOrder({ status: 'shipped' });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order,
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      const messages = ctx.smsAdapter.getSentMessages();
      expect(messages.length).toBe(1);
      expect(messages[0].to).toBe('+15559876543');
      expect(messages[0].body).toContain('confirmed');
      expect(messages[0].body).toContain('shipped');
    });

    it('should skip SMS when user has no phone number', async () => {
      const user = createTestUser({ phone: undefined });
      ctx.userRepo.save(user);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      const messages = ctx.smsAdapter.getSentMessages();
      expect(messages.length).toBe(0);

      // Email and webhook should still be sent
      expect(ctx.emailAdapter.getSentEmails().length).toBe(1);
      expect(ctx.webhookAdapter.getDeliveries().length).toBe(1);
    });
  });

  // ---- Webhook Channel ----

  describe('webhook channel end-to-end', () => {
    it('should deliver webhook notification for order:created', async () => {
      const user = createTestUser();
      ctx.userRepo.save(user);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      const deliveries = ctx.webhookAdapter.getDeliveries();
      expect(deliveries.length).toBe(1);
      expect(deliveries[0].url).toBe('https://hooks.example.com/notify');
      expect(deliveries[0].headers['Content-Type']).toBe('application/json');
      expect(deliveries[0].headers['X-Webhook-Secret']).toBe('test-secret');
      expect(deliveries[0].body.event).toBe('order:confirmation');
      expect(deliveries[0].body.recipient).toBe('alice@example.com');
      expect(deliveries[0].body.subject).toContain('Order Confirmation');
    });

    it('should deliver webhook notification for order:status-changed', async () => {
      const user = createTestUser();
      ctx.userRepo.save(user);
      const order = createTestOrder({ status: 'delivered' });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order,
        previousStatus: 'shipped',
        newStatus: 'delivered',
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      const deliveries = ctx.webhookAdapter.getDeliveries();
      expect(deliveries.length).toBe(1);
      expect(deliveries[0].body.event).toBe('order:status-update');
      expect(deliveries[0].body.body).toContain('shipped');
      expect(deliveries[0].body.body).toContain('delivered');
    });
  });

  // ---- Multi-Channel Dispatch ----

  describe('multi-channel dispatch', () => {
    it('should dispatch to all three channels for order:created when user has phone', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      expect(ctx.emailAdapter.getSentEmails().length).toBe(1);
      expect(ctx.smsAdapter.getSentMessages().length).toBe(1);
      expect(ctx.webhookAdapter.getDeliveries().length).toBe(1);

      // NotificationService in-memory records should have all three
      const records = ctx.notificationService.getNotifications();
      expect(records.length).toBe(3);
      const channels = records.map((r) => r.channel).sort();
      expect(channels).toEqual(['email', 'sms', 'webhook']);
    });

    it('should dispatch to all three channels for order:status-changed when user has phone', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);
      const order = createTestOrder({ status: 'confirmed' });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order,
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      expect(ctx.emailAdapter.getSentEmails().length).toBe(1);
      expect(ctx.smsAdapter.getSentMessages().length).toBe(1);
      expect(ctx.webhookAdapter.getDeliveries().length).toBe(1);
    });
  });

  // ---- History Logging ----

  describe('notification history logging', () => {
    it('should log all sent notifications in history', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      const history = ctx.historyService.getAllHistory();
      expect(history.length).toBe(3); // email + sms + webhook

      // All should be 'sent'
      for (const entry of history) {
        expect(entry.status).toBe('sent');
        expect(entry.type).toBe('order:confirmation');
      }

      const channels = history.map((e) => e.channel).sort();
      expect(channels).toEqual(['email', 'sms', 'webhook']);
    });

    it('should log suppressed notifications in history', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      // Disable email for this user
      ctx.preferencesService.updatePreferences(user.id, {
        email: { enabled: false },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      const history = ctx.historyService.getAllHistory();
      const emailHistory = history.filter((e) => e.channel === 'email');
      const smsHistory = history.filter((e) => e.channel === 'sms');
      const webhookHistory = history.filter((e) => e.channel === 'webhook');

      // Email should be suppressed
      expect(emailHistory.length).toBe(1);
      expect(emailHistory[0].status).toBe('suppressed');

      // SMS and webhook should be sent
      expect(smsHistory.length).toBe(1);
      expect(smsHistory[0].status).toBe('sent');
      expect(webhookHistory.length).toBe(1);
      expect(webhookHistory[0].status).toBe('sent');
    });

    it('should log failed notifications in history', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      // Register a failing email adapter
      const failingEmailAdapter = {
        channel: 'email' as const,
        async send() {
          throw new Error('SMTP connection failed');
        },
      };
      ctx.notificationService.registerAdapter(failingEmailAdapter);

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      };

      await ctx.eventBus.emit(event);

      const history = ctx.historyService.getAllHistory();
      const emailHistory = history.filter((e) => e.channel === 'email');

      expect(emailHistory.length).toBe(1);
      expect(emailHistory[0].status).toBe('failed');
      expect(emailHistory[0].error).toBe('SMTP connection failed');

      // SMS and webhook should still succeed
      const smsHistory = history.filter((e) => e.channel === 'sms');
      const webhookHistory = history.filter((e) => e.channel === 'webhook');
      expect(smsHistory[0].status).toBe('sent');
      expect(webhookHistory[0].status).toBe('sent');
    });

    it('should allow querying history by channel', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      const emailLogs = ctx.historyService.queryHistory({ channel: 'email' });
      expect(emailLogs.length).toBe(1);
      expect(emailLogs[0].channel).toBe('email');

      const smsLogs = ctx.historyService.queryHistory({ channel: 'sms' });
      expect(smsLogs.length).toBe(1);
      expect(smsLogs[0].channel).toBe('sms');
    });
  });

  // ---- User Preferences ----

  describe('user preferences enforcement', () => {
    it('should not send email when email is globally disabled', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      ctx.preferencesService.updatePreferences(user.id, {
        email: { enabled: false },
      });

      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(ctx.emailAdapter.getSentEmails().length).toBe(0);
      // SMS and webhook should still deliver
      expect(ctx.smsAdapter.getSentMessages().length).toBe(1);
      expect(ctx.webhookAdapter.getDeliveries().length).toBe(1);
    });

    it('should not send SMS when SMS is globally disabled', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      ctx.preferencesService.updatePreferences(user.id, {
        sms: { enabled: false },
      });

      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(ctx.smsAdapter.getSentMessages().length).toBe(0);
      // Email and webhook should still deliver
      expect(ctx.emailAdapter.getSentEmails().length).toBe(1);
      expect(ctx.webhookAdapter.getDeliveries().length).toBe(1);
    });

    it('should not send webhook when webhook is globally disabled', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      ctx.preferencesService.updatePreferences(user.id, {
        webhook: { enabled: false },
      });

      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(ctx.webhookAdapter.getDeliveries().length).toBe(0);
      // Email and SMS should still deliver
      expect(ctx.emailAdapter.getSentEmails().length).toBe(1);
      expect(ctx.smsAdapter.getSentMessages().length).toBe(1);
    });

    it('should not send email when order category is disabled for email', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      ctx.preferencesService.updatePreferences(user.id, {
        email: { categories: { order: false } },
      });

      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(ctx.emailAdapter.getSentEmails().length).toBe(0);
      // SMS and webhook should still deliver (their order category is still enabled)
      expect(ctx.smsAdapter.getSentMessages().length).toBe(1);
      expect(ctx.webhookAdapter.getDeliveries().length).toBe(1);
    });

    it('should not send email when frequency is set to none', async () => {
      const user = createTestUser();
      ctx.userRepo.save(user);

      ctx.preferencesService.updatePreferences(user.id, {
        email: { frequency: 'none' },
      });

      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(ctx.emailAdapter.getSentEmails().length).toBe(0);
    });

    it('should suppress all channels when all are disabled', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      ctx.preferencesService.updatePreferences(user.id, {
        email: { enabled: false },
        sms: { enabled: false },
        webhook: { enabled: false },
      });

      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(ctx.emailAdapter.getSentEmails().length).toBe(0);
      expect(ctx.smsAdapter.getSentMessages().length).toBe(0);
      expect(ctx.webhookAdapter.getDeliveries().length).toBe(0);

      // But history should still log suppressions
      const history = ctx.historyService.getAllHistory();
      expect(history.length).toBe(3);
      for (const entry of history) {
        expect(entry.status).toBe('suppressed');
      }
    });

    it('should send to all channels by default (no preferences set)', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);
      // No preferences set — opt-out model means everything is enabled

      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(ctx.emailAdapter.getSentEmails().length).toBe(1);
      expect(ctx.smsAdapter.getSentMessages().length).toBe(1);
      expect(ctx.webhookAdapter.getDeliveries().length).toBe(1);
    });

    it('should allow disabling a specific category on one channel while others remain enabled', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      // Disable order category only for SMS
      ctx.preferencesService.updatePreferences(user.id, {
        sms: { categories: { order: false } },
      });

      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(ctx.emailAdapter.getSentEmails().length).toBe(1);
      expect(ctx.smsAdapter.getSentMessages().length).toBe(0); // suppressed
      expect(ctx.webhookAdapter.getDeliveries().length).toBe(1);
    });
  });

  // ---- Notification Ordering ----

  describe('notification ordering', () => {
    it('should deliver notifications in the order events are emitted', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);
      const order = createTestOrder();

      const createdEvent: OrderCreatedEvent = {
        type: 'order:created',
        order,
        user,
        timestamp: new Date(),
      };

      const statusEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: { ...order, status: 'confirmed' },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      // Emit both events (EventBus serializes them)
      await ctx.eventBus.emit(createdEvent);
      await ctx.eventBus.emit(statusEvent);

      const records = ctx.notificationService.getNotifications();

      // First 3 should be order:confirmation (email, sms, webhook)
      const confirmations = records.filter((r) => r.type === 'order:confirmation');
      const statusUpdates = records.filter((r) => r.type === 'order:status-update');

      expect(confirmations.length).toBe(3);
      expect(statusUpdates.length).toBe(3);

      // All confirmations should come before all status-updates in the array
      const lastConfirmationIndex = records.findLastIndex((r) => r.type === 'order:confirmation');
      const firstStatusUpdateIndex = records.findIndex((r) => r.type === 'order:status-update');
      expect(lastConfirmationIndex).toBeLessThan(firstStatusUpdateIndex);
    });

    it('should maintain order even when events are emitted without awaiting', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);
      const order = createTestOrder();

      const createdEvent: OrderCreatedEvent = {
        type: 'order:created',
        order,
        user,
        timestamp: new Date(),
      };

      const statusEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: { ...order, status: 'confirmed' },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      // Emit concurrently without awaiting first
      const p1 = ctx.eventBus.emit(createdEvent);
      const p2 = ctx.eventBus.emit(statusEvent);
      await Promise.all([p1, p2]);

      const records = ctx.notificationService.getNotifications();
      const types = records.map((r) => r.type);

      // All order:confirmation should come before order:status-update
      const lastConfIdx = types.lastIndexOf('order:confirmation');
      const firstStatusIdx = types.indexOf('order:status-update');
      expect(lastConfIdx).toBeLessThan(firstStatusIdx);
    });
  });

  // ---- Error Resilience ----

  describe('error resilience', () => {
    it('should continue delivering to other channels when one adapter fails', async () => {
      const user = createTestUser({ phone: '+15551112222' });
      ctx.userRepo.save(user);

      // Replace email adapter with one that fails
      ctx.notificationService.registerAdapter({
        channel: 'email' as const,
        async send() {
          throw new Error('Email server down');
        },
      });

      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      // Email failed, but SMS and webhook should still succeed
      expect(ctx.smsAdapter.getSentMessages().length).toBe(1);
      expect(ctx.webhookAdapter.getDeliveries().length).toBe(1);

      // History shows the failure
      const history = ctx.historyService.getAllHistory();
      const emailLog = history.find((e) => e.channel === 'email');
      expect(emailLog?.status).toBe('failed');
      expect(emailLog?.error).toBe('Email server down');
    });

    it('should continue processing subsequent events after an adapter failure', async () => {
      const user = createTestUser();
      ctx.userRepo.save(user);

      let shouldFail = true;
      ctx.notificationService.registerAdapter({
        channel: 'email' as const,
        async send() {
          if (shouldFail) {
            shouldFail = false;
            throw new Error('Transient failure');
          }
        },
      });

      // First event — email will fail
      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder(),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      // Second event — email should succeed (shouldFail is now false)
      await ctx.eventBus.emit({
        type: 'order:created',
        order: createTestOrder({ id: 'order-002' }),
        user,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      const history = ctx.historyService.getAllHistory();
      const emailLogs = history.filter((e) => e.channel === 'email');
      expect(emailLogs.length).toBe(2);
      expect(emailLogs[0].status).toBe('failed');
      expect(emailLogs[1].status).toBe('sent');
    });
  });

  // ---- UserRepository Phone Persistence ----

  describe('user phone number persistence (bug regression)', () => {
    it('should persist and retrieve user phone number through repository', () => {
      const user = createTestUser({ phone: '+15559999999' });
      ctx.userRepo.save(user);

      const retrieved = ctx.userRepo.findById(user.id);
      expect(retrieved).toBeDefined();
      expect(retrieved!.phone).toBe('+15559999999');
    });

    it('should handle user without phone number', () => {
      const user = createTestUser({ phone: undefined });
      ctx.userRepo.save(user);

      const retrieved = ctx.userRepo.findById(user.id);
      expect(retrieved).toBeDefined();
      expect(retrieved!.phone).toBeUndefined();
    });
  });
});

